//Type writing Heading-----------------------------
const type = document.getElementById("typing");
const text = "Welcome to Village Hirauli";
let i = 0;
function write(){
    if(i < text.length){
        type.innerHTML += text.charAt(i);
        i++;
        setTimeout(write,50);
    }
}
window.onload = write();

// Disappear logo while scrolling-----------------

window.addEventListener("scroll", function (){
        const imgLogo = document.getElementById("main");
        if(window.scrollY > 50){
            imgLogo.style.opacity = "0";
        }else{
            imgLogo.style.opacity = "1";
        }
    });





