// SLIDER SYSTEM ------------------------------

const slides  = document.getElementById('slideContainer');
const dotsEl  = document.getElementById('sliderDots');
const TOTAL   = 5;   // real slides
const TOTAL_W = 6;   // total width slots (5 + 1 copy)
let index     = 0;   // 0..4 (real index)
let timer     = null;
let locked    = false; // transition chal rahi hai

// ── Dots banao (sirf 5) ──
for (let i = 0; i < TOTAL; i++) {
    const d = document.createElement('div');
    d.className = 'dot' + (i === 0 ? ' active' : '');
    d.onclick = () => jumpTo(i);
    dotsEl.appendChild(d);
}

function updateDots(i) {
    document.querySelectorAll('.dot').forEach((d, n) => {
        d.classList.toggle('active', n === i);
    });
}

// translateX calculate: based on TOTAL_W slots
function posOf(i) {
    return -i * (100 / TOTAL_W);
}

function goToSlide(i, animate) {
    slides.style.transition = animate ? 'transform 0.5s ease-in-out' : 'none';
    slides.style.transform  = `translateX(${posOf(i)}%)`;
    updateDots(i % TOTAL);
}

// ── Next slide (auto ya button) ──
function nextSlide() {
    if (locked) return;
    locked = true;

    if (index === TOTAL - 1) {
        // index 4 → copy (index 5) → silently back to 0
        goToSlide(TOTAL, true); // copy pe jao (smooth)
        setTimeout(() => {
            goToSlide(0, false); // silently pehli pe
            index  = 0;
            locked = false;
        }, 520);
    } else {
        index++;
        goToSlide(index, true);
        setTimeout(() => { locked = false; }, 520);
    }
}

function prevSlide() {
    if (locked) return;
    locked = true;
    index = (index - 1 + TOTAL) % TOTAL;
    goToSlide(index, true);
    setTimeout(() => { locked = false; }, 520);
}

function jumpTo(i) {
    if (locked) return;
    resetTimer();
    index = i;
    goToSlide(index, true);
}

// ── Manual buttons ──
function manualSlide(dir) {
    resetTimer();
    if (dir > 0) nextSlide(); else prevSlide();
}
window.manualSlide = manualSlide;

// ── Auto timer ──
function startTimer() {
    timer = setInterval(nextSlide, 3000);
}
function resetTimer() {
    clearInterval(timer);
    startTimer();
}

// ── Touch / Mouse swipe ──
let startX = 0, isDragging = false, dragDelta = 0;

function onDragStart(x) {
    if (locked) return;
    startX     = x;
    isDragging = true;
    dragDelta  = 0;
    slides.classList.add('dragging');
    resetTimer();
}
function onDragMove(x) {
    if (!isDragging) return;
    dragDelta = x - startX;
    const base  = posOf(index);
    const shift = (dragDelta / slides.parentElement.offsetWidth) * 100;
    slides.style.transition = 'none';
    slides.style.transform  = `translateX(${base + shift}%)`;
}
function onDragEnd() {
    if (!isDragging) return;
    isDragging = false;
    slides.classList.remove('dragging');
    const threshold = slides.parentElement.offsetWidth * 0.2;
    if      (dragDelta < -threshold) nextSlide();
    else if (dragDelta >  threshold) prevSlide();
    else goToSlide(index, true); // wapas same pe
}

slides.addEventListener('mousedown',  e => onDragStart(e.clientX));
slides.addEventListener('mousemove',  e => onDragMove(e.clientX));
slides.addEventListener('mouseup',    onDragEnd);
slides.addEventListener('mouseleave', onDragEnd);
slides.addEventListener('touchstart', e => onDragStart(e.touches[0].clientX), { passive: true });
slides.addEventListener('touchmove',  e => onDragMove(e.touches[0].clientX),  { passive: true });
slides.addEventListener('touchend',   onDragEnd);

// Start
startTimer();

// WEATHER SYSTEM --------------------------------

const weatherSpan = document.getElementById("weather");
const apiKey = "d1555b0a00821aceaa7cfa201414a848";
const city = "Shahabad, Hardoi, IN";

async function getWeather() {
  try {
    const response = await fetch(
      `https://api.openweathermap.org/data/2.5/weather?q=${encodeURIComponent(city)}&appid=${apiKey}&units=metric`
    );

    const data = await response.json();

    if (!response.ok) {
      weatherSpan.innerHTML = "❌ Weather unavailable";
      console.log(data);
      return;
    }

    const temp = Math.round(data.main.temp);
    const condition = data.weather[0].main;
    const description = data.weather[0].description;

    let emoji = "🌤️";

    switch (condition) {
      case "Clear":
        emoji = "☀️";
        break;
      case "Clouds":
        emoji = "☁️";
        break;
      case "Rain":
        emoji = "🌧️";
        break;
      case "Drizzle":
        emoji = "🌦️";
        break;
      case "Thunderstorm":
        emoji = "⛈️";
        break;
      case "Snow":
        emoji = "❄️";
        break;
      case "Mist":
      case "Fog":
      case "Haze":
        emoji = "🌫️";
        break;
    }

    weatherSpan.innerHTML = `${emoji} ${temp}°C • ${description}`;
  } catch (err) {
    weatherSpan.innerHTML = "⚠️ Failed to load weather";
    console.error(err);
  }
}

getWeather();


